insert into public.content_snapshots (locale, status, content, updated_at, published_at)
values
  ('nb', 'published', '{"contacts":[{"email":"miriam.svendsen@globalworking.net","name":"Miriam Svendsen","phone":"+47 919 00 649","role":"Rekrutteringsansvarlig"},{"email":"gro.anette@globalworking.net","name":"Gro Anette","phone":"+47 408 98 448","role":"KandidatoppfГѓВёlging"}],"ctaBanner":{"badge":"Klar til ГѓВҐ starte?","cta1":"Kontakt oss nГѓВҐ","cta2":"Se kandidater","description":"Vi kobler norske arbeidsgivere med kandidater som er sprГѓВҐklig og faglig forberedt for trygg oppstart.","heading":"Finn riktig kompetanse for din virksomhet i dag"},"faq":{"ctaText":"Fant du ikke svaret? Kontakt oss","description":"Finn svar pГѓВҐ de vanligste spГѓВёrsmГѓВҐlene om rekruttering og samarbeid med Global Working.","heading":"Ofte stilte spГѓВёrsmГѓВҐl","items":[{"a":"Tidslinjen avhenger av valgt opplГѓВ¦ringslГѓВёp: fysisk (5 mГѓВҐneder), hybrid (7 mГѓВҐneder) eller fullt nettbasert (9 mГѓВҐneder). Intervjuer med arbeidsgiver skjer normalt 1Гўв‚¬вЂњ4 uker etter opplГѓВ¦ring.","q":"Hvor lang tid tar rekrutteringsprosessen?"},{"a":"Kandidatene fГѓВёlger et strukturert lГѓВёp med opptil 600 undervisningstimer i norsk, bransjespesifikk terminologi og innfГѓВёring i norsk arbeidskultur. MГѓВҐlet settes ut fra rollekrav, ofte opp mot B2.","q":"Hvilket sprГѓВҐknivГѓВҐ har kandidatene nГѓВҐr de ankommer Norge?"},{"a":"Vi rekrutterer primГѓВ¦rt til helse og omsorg, industri og bygg, samt utdanning og barneomsorg. Helsesektoren er vГѓВҐrt spesialfelt, der vi har levert kvalifiserte sykepleiere siden 2015.","q":"Hvilke sektorer dekker dere?"},{"a":"Pris avhenger av behov og omfang. Vi gГѓВҐr gjennom modell og priser i et uforpliktende kartleggingsmГѓВёte, slik at lГѓВёsningen tilpasses virksomheten deres.","q":"Hva koster det ГѓВҐ bruke Global Working?"},{"a":"Vi kombinerer seleksjon, sprГѓВҐkforberedelse og tett oppfГѓВёlging fГѓВёr oppstart. Teamet vГѓВҐrt inkluderer bГѓВҐde psykologer og sprГѓВҐklГѓВ¦rere, og prosessene er ISO-sertifiserte.","q":"Hvordan sikrer dere kvaliteten pГѓВҐ kandidatene?"},{"a":"Ja. Vi fГѓВёlger opp kandidaten og arbeidsgiveren gjennom prГѓВёveperioden med ekstra sprГѓВҐktimer, stГѓВёtte med dokumentasjon og jevnlige samtalepunkter for ГѓВҐ sikre en vellykket integrering.","q":"Tilbyr dere oppfГѓВёlging etter ansettelse?"}],"label":"SpГѓВёrsmГѓВҐl & svar"},"footer":{"description":"Rekruttering og sprГѓВҐkopplГѓВ¦ring for kvalifiserte fagfolk til det norske arbeidsmarkedet, med strukturert oppfГѓВёlging fra fГѓВёrste kontakt til oppstart.","links":{"Kontakt":[{"href":"mailto:Miriam.Svendsen@globalworking.net","label":"Miriam.Svendsen@globalworking.net"},{"href":"tel:+4791900649","label":"+47 919 00 649"},{"href":"mailto:Gro.anette@globalworking.net","label":"Gro.anette@globalworking.net"},{"href":"tel:+4740898448","label":"+47 408 98 448"}],"Selskapet":[{"href":"/om-oss","label":"Om oss"},{"href":"/nyheter","label":"Nyheter"},{"href":"/kontakt","label":"Kontakt"},{"href":"/#personvern","label":"Personvern"}],"Tjenester":[{"href":"/vr-rekrutteringsmodell","label":"VГѓВҐr rekrutteringsmodell"},{"href":"/helse","label":"Helsesektor"},{"href":"/talentportalen","label":"Talentportalen"},{"href":"/kontakt","label":"Kontakt"}]},"social":[{"href":"https://www.linkedin.com/company/globalworking-norge","label":"LinkedIn"},{"href":"https://www.instagram.com/globalworkingnorge","label":"Instagram"}]},"godeGrunner":{"articleLink":"/nyheter/sor-fron-integrasjon","articleLinkLabel":"Les artikkel","description":"Mangelen pГѓВҐ helsepersonell kombinert med sykefravГѓВ¦r og permisjoner gjГѓВёr det nГѓВёdvendig ГѓВҐ finne varige lГѓВёsninger pГѓВҐ arbeidskraft for ГѓВҐ gi pasientene oppfГѓВёlgingen de trenger.","heading":"Hva sier kommunene vi samarbeider med?","label":"Et samarbeid som gir nye lГѓВёsninger","testimonials":[{"author":"Karin, ГѓвЂ¦mot kommune","quote":"Vi har vГѓВ¦rt veldig fornГѓВёyd med to av vГѓВҐre sykepleiere fra Spania. SprГѓВҐket var mye bedre enn forventet, og de passet godt inn hos oss."},{"author":"Daniel, Kautokeino kommune","quote":"Vi fant en god lГѓВёsning med ГѓВҐ la en sykepleier jobbe i helsefagarbeider-stilling til hun var bedre i sprГѓВҐket. Tre-fire uker etterpГѓВҐ var hun klar til ГѓВҐ jobbe fast som sykepleier hos oss."},{"author":"Anne, Trondheim kommune","quote":"Vi var veldig glade for ГѓВҐ fГѓВҐ en sykepleier fra Italia som en del av teamet vГѓВҐrt. Han lГѓВ¦rte seg sprГѓВҐket fort nГѓВҐr han begynte ГѓВҐ jobbe."}]},"helseHero":{"description":"Vi forbereder helsepersonell for den norske helsesektoren Гўв‚¬вЂњ fra sprГѓВҐkopplГѓВ¦ring til trygg oppstart i jobb.","h1":"Tjenester for helseinstitusjoner"},"helsePartnership":{"cta1":"Kontakt oss","cta2":"Se kandidatportalen","heading":"Slik samarbeider vi med dere","label":"Samarbeidsmodell","p1":"Global Working er ikke et bemanningsbyrГѓВҐ. Vi forbereder kandidatene gjennom strukturert opplГѓВ¦ring. Deretter ansetter dere kandidaten direkte Гўв‚¬вЂњ uten mellomledd.","p2":"Gjennom vГѓВҐr nye kandidatportal kan arbeidsgivere selv se tilgjengelige kandidater og invitere til intervju."},"helsePhases":{"description":"VГѓВҐr prosess er delt inn i tre faser for ГѓВҐ sikre at kandidatene er godt forberedt fГѓВёr de starter i jobb.","heading":"Slik rekrutterer vi sykepleiere til Norge","label":"Rekrutteringsprosessen","phases":[{"description":"Kandidatene gjennomfГѓВёrer opptil 600 undervisningstimer i norsk, helseterminologi og praktisk sprГѓВҐkbruk i kliniske situasjoner.","formats":[{"duration":"5 mГѓВҐneder","label":"Fysisk i Alicante"},{"duration":"7 mГѓВҐneder","label":"Kombinasjon fysisk og nett"},{"duration":"9 mГѓВҐneder","label":"Full nettbasert opplГѓВ¦ring"}],"number":"01","title":"SprГѓВҐk og faglig forberedelse"},{"description":"1Гўв‚¬вЂњ4 uker etter avsluttet opplГѓВ¦ring gjennomfГѓВёres intervju med arbeidsgivere. Vi koordinerer oppstart og avreisedato med begge parter.","formats":null,"number":"02","title":"Strukturert overgang"},{"description":"Ved behov tilrettelegger vi individuell sprГѓВҐktrening fГѓВёr og etter avreise. Vi kjГѓВёrer 17Гўв‚¬вЂњ20 opplГѓВ¦ringsgrupper ГѓВҐrlig for ГѓВҐ sikre kontinuitet.","formats":null,"number":"03","title":"Ekstra oppfГѓВёlging"}]},"helsesektorComp":{"blockquote":{"author":"Kristina S, VГѓВҐgГѓВҐ kommune","text":"Vi ГѓВёnsket ГѓВҐ tilby 6 sykepleiere fast stilling gjennom samarbeid med Global Working. For oss ble dette en god lГѓВёsning pГѓВҐ bemanningskrisen vi hadde."},"ctaLabel":"Be om kandidater","description":"Global Working er den stГѓВёrste leverandГѓВёren av sykepleiere utenfra Skandinavia til Norge. Siden 2014 har vi spesialisert oss pГѓВҐ ГѓВҐ utdanne og kvalifisere sykepleiere for arbeid i Norge.","features":[{"description":"Kandidatene fГѓВҐr opptil 600 undervisningstimer i norsk, helseterminologi og praktisk sprГѓВҐkbruk i kliniske situasjoner.","title":"SprГѓВҐk og faglig forberedelse fГѓВёr ansettelse"},{"description":"Fysisk i Alicante (5 mГѓВҐneder), kombinasjon fysisk og nett (7 mГѓВҐneder), eller full nettbasert opplГѓВ¦ring (9 mГѓВҐneder).","title":"Tre opplГѓВ¦ringsmodeller"},{"description":"Intervju skjer 1Гўв‚¬вЂњ4 uker etter avsluttet opplГѓВ¦ring. Vi koordinerer oppstart og avreisedato med begge parter.","title":"Strukturert overgang til arbeidsgiver"},{"description":"Vi kan tilrettelegge individuell sprГѓВҐktrening fГѓВёr og etter avreise for ГѓВҐ redusere usikkerhet i oppstarten.","title":"Ekstra oppfГѓВёlging ved behov"}],"groupsLabel":"grupper ГѓВҐrlig","groupsValue":"17Гўв‚¬вЂњ20","heading":"Vi forbereder helsepersonell for den norske helsesektoren","label":"Tjenester for helseinstitusjoner","stats":[{"label":"erfaring i Norge","value":"10+ ГѓВҐr"},{"label":"undervisningstimer i norsk","value":"25 000+"},{"label":"timer opplГѓВ¦ring (opptil)","value":"600"}]},"hero":{"badge":"Norges ledende rekrutteringspartner","cta1":"Slik jobber vi","cta2":"Kontakt oss","description":"Global Working er verdens stГѓВёrste sprГѓВҐkskole som underviser i norsk utenfor Skandinavia. Vi spesialiserer oss pГѓВҐ norsk sprГѓВҐk- og kulturopplГѓВ¦ring for sГѓВёreuropeiske fagfolk, og kobler dem med arbeidsgivere i Norge. Vi fГѓВёlger kandidatene fra fГѓВёrste norsktime til trygg oppstart i jobb.","h1First":"Har dere behov for","h1Highlight":"arbeidskraft?","stats":[{"animate":false,"label":"Grunnlagt","value":"2014"},{"animate":true,"label":"Ansatte","value":"50+"},{"animate":true,"label":"Kandidater plassert i Norge","value":"500+"},{"animate":true,"label":"Retensjonsgrad","value":"95%"}]},"homeContact":{"cta":"Send oss en melding","description":"Du treffer oss pГѓВҐ e-post eller telefon. Vi tar kontakt sГѓВҐ snart vi har mulighet.","heading":"ГѓЛњnsker du ГѓВҐ vite mer?","label":"Kontakt"},"homeHealth":{"cta":"Les mer om helse","description":"Global Working er den stГѓВёrste leverandГѓВёren av sykepleiere utenfra Skandinavia til Norge. Siden 2014 har vi spesialisert oss pГѓВҐ ГѓВҐ utdanne og kvalifisere sykepleiere fra Spania, Italia og Frankrike for arbeid i norsk helsesektor.","heading":"Vi stГѓВёtter det norske helsevesenet","label":"Helsesektoren"},"homeServices":{"description":"Vi kobler norske arbeidsgivere med kvalifiserte fagfolk fra SГѓВёr-Europa Гўв‚¬вЂњ forberedt med sprГѓВҐk, kultur og fagkompetanse.","heading":"VГѓВҐrt tilbud til norske arbeidsgivere","label":"VГѓВҐre tjenester","sections":[{"description":"Vi finner, forbereder og fГѓВёlger opp fagfolk fra SГѓВёr-Europa til trygg oppstart i Norge. Opptil 600 timer norskopplГѓВ¦ring.","href":"/vr-rekrutteringsmodell","title":"VГѓВҐr rekrutteringsmodell"},{"description":"Norges stГѓВёrste leverandГѓВёr av sykepleiere utenfra Skandinavia. Spesialisert helsefaglig forberedelse siden 2014.","href":"/helse","title":"Helsesektor"},{"description":"Se tilgjengelige kandidater for fast ansettelse direkte i vГѓВҐr nye kandidatportal.","href":"/talentportalen","title":"Talentportalen"},{"description":"Grunnlagt i 2014. 50+ ansatte. ISO-sertifisert. Hovedkontor i Alicante med kontor i Oslo.","href":"/om-oss","title":"Om Global Working"}]},"homeStats":[{"label":"Kandidater plassert i Norge","value":"500+"},{"label":"Retensjonsgrad","value":"95%"},{"label":"Undervisningstimer i norsk","value":"25 000+"}],"hvaGjor":{"ctaLabel":"Book et mГѓВёte med oss","ctaNote":"Uforpliktende kartlegging av behov","description":"Vi finner og presenterer de mest relevante menneskene til din virksomhet, og fГѓВёlger prosessen helt frem til trygg oppstart.","heading":"Hva gjГѓВёr Global Working?","label":"VГѓВҐr prosess","services":[{"description":"Vi rekrutterer kompetansen dere trenger innen flere sektorer, blant annet helse og omsorg, industri og bygg, samt utdanning og barneomsorg.","title":"Rekrutterer kompetanse"},{"description":"Vi underviser fra ingen forkunnskaper til opptil B2-nivГѓВҐ, og tilpasser sprГѓВҐk, rolle og arbeidshverdag til mГѓВҐlene dere har satt.","title":"SГѓВёrger for ГѓВёnsket sprГѓВҐknivГѓВҐ"},{"description":"Vi hjelper kandidatene gjennom hele prosessen med nГѓВёdvendige dokumenter og riktig papirarbeid, med ekstra sprГѓВҐktimer ved behov.","title":"Trygg oppstart i Norge"}]},"kontaktComp":{"description":"Du treffer oss pГѓВҐ e-post eller telefon, eller ved ГѓВҐ fylle ut skjemaet under. Vi tar kontakt sГѓВҐ snart vi har mulighet.","heading":"ГѓЛњnsker du ГѓВҐ vite mer?","label":"Kontakt","officeAddress":"Carrer de Periodista Pirula Arderius, 4, 03001 Alicante, EspaГѓВ±a","officeTitle":"Hovedkontor Alicante"},"kontaktHero":{"description":"Vi er tilgjengelige for spГѓВёrsmГѓВҐl om rekruttering, samarbeid og kandidatportal. Ta kontakt Гўв‚¬вЂњ vi svarer normalt innen 1 virkedag.","h1":"Kontakt oss"},"navbar":{"ctaLabel":"Kom i gang","links":[{"href":"/vr-rekrutteringsmodell","label":"VГѓВҐr rekrutteringsmodell"},{"href":"/helse","label":"Helsesektor"},{"href":"/nyheter","label":"Nyheter"},{"href":"/talentportalen","label":"Talentportalen"},{"href":"/om-oss","label":"Om oss"},{"href":"/kontakt","label":"Kontakt"}]},"nyheterHero":{"description":"FГѓВёlg med pГѓВҐ siste nytt fra Global Working Гўв‚¬вЂњ artikler, oppdateringer og historier fra vГѓВҐrt arbeid med rekruttering og sprГѓВҐkopplГѓВ¦ring.","h1":"Nyheter & Artikler"},"omOssComp":{"blockquote":{"author":"Pablo, CEO Global Working","text":"For oss handler internasjonal rekruttering ikke bare om ГѓВҐ fylle en stilling. Det handler om ГѓВҐ forberede mennesker grundig, slik at bГѓВҐde arbeidsgiver og kandidat fГѓВҐr en trygg start og et langsiktig samarbeid."},"heading":"Hvem er Global Working?","label":"Om oss","locationLabel":"Alicante","locationSub":"Hovedkontor med kontor i Oslo","p1":"Global Working er en spesialisert aktГѓВёr innen sprГѓВҐkopplГѓВ¦ring og internasjonal rekruttering i Europa. Vi forbereder kandidater fГѓВёr ansettelse, slik at arbeidsgivere fГѓВҐr medarbeidere og grunnlag for varige ansettelser.","p2":"Global Working ble etablert i 2014 med mГѓВҐl om ГѓВҐ gjГѓВёre det enklere for fagpersoner ГѓВҐ bevege seg i det europeiske arbeidsmarkedet. I dag kombinerer vi rekruttering, sprГѓВҐkopplГѓВ¦ring og tett oppfГѓВёlging for ГѓВҐ sikre forutsigbare og bГѓВ¦rekraftige ansettelser.","stats":[{"label":"Etablert","value":"2014"},{"label":"Ansatte","value":"50"},{"label":"Sertifisert","value":"ISO"}],"values":[{"desc":"25 % av teamet er psykologer som jobber med seleksjon, vurdering og oppfГѓВёlging av kandidater.","title":"Seleksjon med faglig vurdering"},{"desc":"55 % av teamet er sprГѓВҐklГѓВ¦rere med spesialisering i yrkesrettet sprГѓВҐkopplГѓВ¦ring.","title":"Yrkesrettet sprГѓВҐkopplГѓВ¦ring"},{"desc":"Vi er ISO-sertifisert for sprГѓВҐkundervisning og internasjonal rekruttering i Europa.","title":"Kvalitetssikret prosess"}]},"omOssHero":{"description":"Global Working er en spesialisert aktГѓВёr innen sprГѓВҐkopplГѓВ¦ring og internasjonal rekruttering.","h1":"Om oss"},"omOssOffices":{"description":"Global Working har hovedkontor i Alicante, Spania, med kontor i Oslo.","heading":"VГѓВҐre kontorer","label":"Lokasjon","officeAddress":"Carrer de Periodista Pirula Arderius, 4, 03001 Alicante, EspaГѓВ±a","officeName":"Hovedkontor Гўв‚¬вЂќ Alicante"},"omOssTeam":{"description":"VГѓВҐrt flerfaglige team av psykologer, sprГѓВҐklГѓВ¦rere og rekrutteringsspesialister sikrer en helhetlig prosess Гўв‚¬вЂќ fra utvelgelse og opplГѓВ¦ring til oppfГѓВёlging i Norge.","heading":"MГѓВёt teamet i Global Working","label":"VГѓВҐrt team","members":[{"hasImage":true,"initials":"PS","name":"Pablo Santamarina","role":"CEO & Grunnlegger"},{"hasImage":false,"initials":"MS","name":"Miriam Svendsen","role":"Rekrutteringsansvarlig"},{"hasImage":false,"initials":"GA","name":"Gro Anette","role":"KandidatoppfГѓВёlging"},{"hasImage":false,"initials":"T","name":"Teamet","role":"50+ ansatte i Alicante og Oslo"}]},"rekrutteringCollab":{"cta1":"Kontakt oss","cta2":"Se kandidatportalen","heading":"Slik samarbeider vi med dere","label":"Samarbeidsmodell","p1":"Global Working er ikke et bemanningsbyrГѓВҐ. Vi forbereder kandidatene gjennom strukturert opplГѓВ¦ring. Deretter ansetter dere kandidaten direkte Гўв‚¬вЂњ uten mellomledd.","p2":"Samarbeidet starter med en uforpliktende kartlegging av ditt behov. Vi presenterer sГѓВҐ kvalifiserte kandidater som matcher kravene dere har satt.","p3":"Gjennom vГѓВҐr nye kandidatportal kan arbeidsgivere selv se tilgjengelige kandidater og invitere til intervju."},"rekrutteringComp":{"badge":"Strukturert modell siden 2014","heading":"Slik rekrutterer vi fagfolk til Norge","label":"VГѓВҐr rekrutteringsmodell","p1":"VГѓВҐre kandidater kommer hovedsakelig fra Spania, Italia og Frankrike, og er motiverte fagpersoner som ГѓВёnsker ГѓВҐ jobbe i Norge over lengre tid eller etablere seg her pГѓВҐ sikt.","p2":"Undervisningen kan gjennomfГѓВёres fysisk i Alicante (5 mГѓВҐneder), som kombinasjon av fysisk og nettbasert undervisning (7 mГѓВҐneder), eller fullt nettbasert (9 mГѓВҐneder).","sectors":["Helse og omsorg","Industri og bygg","Utdanning","Barneomsorg"],"steps":[{"description":"Vi kartlegger kompetanse, motivasjon og ГѓВёnsker fГѓВёr kandidatene presenteres for arbeidsgiver.","title":"Rekrutterer kompetansen du trenger"},{"description":"Alle kandidater fГѓВёlger et strukturert lГѓВёp med opptil 600 timer norsk, bransjeterminologi og arbeidskultur.","title":"SprГѓВҐk og faglig forberedelse"},{"description":"1Гўв‚¬вЂњ4 uker etter opplГѓВ¦ring gjennomfГѓВёres intervju med arbeidsgivere, og oppstart og avreisedato avtales.","title":"Strukturert overgang"},{"description":"Ved behov tilrettelegger vi individuelt opplegg med ekstra sprГѓВҐktrening fГѓВёr eller etter avreise.","title":"Ekstra oppfГѓВёlging ved behov"}]},"rekrutteringHero":{"description":"Vi finner og presenterer de mest relevante menneskene til din virksomhet, og fГѓВёlger prosessen helt frem til trygg oppstart.","h1":"Hva gjГѓВёr Global Working?"},"talentportalenBenefits":{"heading":"Fordeler med kandidatportalen","items":["Sanntidsoversikt over tilgjengelige kandidater","Detaljerte profiler med sprГѓВҐknivГѓВҐ og erfaring","Direkte kommunikasjon med rekrutteringsteamet","Gratis tilgang for arbeidsgivere som samarbeider med oss"],"label":"Hvorfor portalen"},"talentportalenComp":{"benefits":[{"desc":"FГѓВҐ oversikt over tilgjengelige kandidater og finn profiler som passer deres behov.","title":"Se kandidater for fast ansettelse"},{"desc":"Arbeidsgivere kan selv gГѓВҐ gjennom profiler og invitere aktuelle kandidater til intervju.","title":"Inviter til intervju direkte"},{"desc":"Se status i sprГѓВҐk- og faglig forberedelse, slik at oppstarten kan planlegges tryggere.","title":"Oversikt over sprГѓВҐkforberedelse"},{"desc":"Portalen er koblet til rekrutteringsteamet vГѓВҐrt for korte avklaringer underveis.","title":"Rask dialog med oss"}],"ctaContact":"Kontakt oss","ctaLogin":"Logg inn pГѓВҐ portalen","description":"Global Working har fГѓВҐtt ny kandidatportal. NГѓВҐ kan du selv gГѓВҐ inn og se hvilke kandidater vi har tilgjengelig for fast ansettelse.","heading":"Ny kandidatportal for arbeidsgivere","label":"Talentportalen","portalUrl":"https://globalworking-talentportal.lovable.app"},"talentportalenHero":{"description":"Se tilgjengelige kandidater og inviter til intervju direkte gjennom vГѓВҐr nye plattform.","h1":"Kandidatportal for arbeidsgivere"},"talentportalenSteps":{"heading":"Slik bruker du portalen","label":"Steg for steg","steps":[{"desc":"Ta kontakt med oss for ГѓВҐ fГѓВҐ tilgang til kandidatportalen.","number":"01","title":"Opprett konto"},{"desc":"Se profiler, sprГѓВҐknivГѓВҐ, fagbakgrunn og tilgjengelighet.","number":"02","title":"Bla gjennom kandidater"},{"desc":"Velg kandidater som passer og inviter dem direkte til intervju.","number":"03","title":"Inviter til intervju"},{"desc":"Dere ansetter kandidaten direkte Гўв‚¬вЂњ uten mellomledd.","number":"04","title":"Ansett direkte"}]}}'::jsonb, now(), now()),
  ('nb', 'draft', '{"contacts":[{"email":"miriam.svendsen@globalworking.net","name":"Miriam Svendsen","phone":"+47 919 00 649","role":"Rekrutteringsansvarlig"},{"email":"gro.anette@globalworking.net","name":"Gro Anette","phone":"+47 408 98 448","role":"KandidatoppfГѓВёlging"}],"ctaBanner":{"badge":"Klar til ГѓВҐ starte?","cta1":"Kontakt oss nГѓВҐ","cta2":"Se kandidater","description":"Vi kobler norske arbeidsgivere med kandidater som er sprГѓВҐklig og faglig forberedt for trygg oppstart.","heading":"Finn riktig kompetanse for din virksomhet i dag"},"faq":{"ctaText":"Fant du ikke svaret? Kontakt oss","description":"Finn svar pГѓВҐ de vanligste spГѓВёrsmГѓВҐlene om rekruttering og samarbeid med Global Working.","heading":"Ofte stilte spГѓВёrsmГѓВҐl","items":[{"a":"Tidslinjen avhenger av valgt opplГѓВ¦ringslГѓВёp: fysisk (5 mГѓВҐneder), hybrid (7 mГѓВҐneder) eller fullt nettbasert (9 mГѓВҐneder). Intervjuer med arbeidsgiver skjer normalt 1Гўв‚¬вЂњ4 uker etter opplГѓВ¦ring.","q":"Hvor lang tid tar rekrutteringsprosessen?"},{"a":"Kandidatene fГѓВёlger et strukturert lГѓВёp med opptil 600 undervisningstimer i norsk, bransjespesifikk terminologi og innfГѓВёring i norsk arbeidskultur. MГѓВҐlet settes ut fra rollekrav, ofte opp mot B2.","q":"Hvilket sprГѓВҐknivГѓВҐ har kandidatene nГѓВҐr de ankommer Norge?"},{"a":"Vi rekrutterer primГѓВ¦rt til helse og omsorg, industri og bygg, samt utdanning og barneomsorg. Helsesektoren er vГѓВҐrt spesialfelt, der vi har levert kvalifiserte sykepleiere siden 2015.","q":"Hvilke sektorer dekker dere?"},{"a":"Pris avhenger av behov og omfang. Vi gГѓВҐr gjennom modell og priser i et uforpliktende kartleggingsmГѓВёte, slik at lГѓВёsningen tilpasses virksomheten deres.","q":"Hva koster det ГѓВҐ bruke Global Working?"},{"a":"Vi kombinerer seleksjon, sprГѓВҐkforberedelse og tett oppfГѓВёlging fГѓВёr oppstart. Teamet vГѓВҐrt inkluderer bГѓВҐde psykologer og sprГѓВҐklГѓВ¦rere, og prosessene er ISO-sertifiserte.","q":"Hvordan sikrer dere kvaliteten pГѓВҐ kandidatene?"},{"a":"Ja. Vi fГѓВёlger opp kandidaten og arbeidsgiveren gjennom prГѓВёveperioden med ekstra sprГѓВҐktimer, stГѓВёtte med dokumentasjon og jevnlige samtalepunkter for ГѓВҐ sikre en vellykket integrering.","q":"Tilbyr dere oppfГѓВёlging etter ansettelse?"}],"label":"SpГѓВёrsmГѓВҐl & svar"},"footer":{"description":"Rekruttering og sprГѓВҐkopplГѓВ¦ring for kvalifiserte fagfolk til det norske arbeidsmarkedet, med strukturert oppfГѓВёlging fra fГѓВёrste kontakt til oppstart.","links":{"Kontakt":[{"href":"mailto:Miriam.Svendsen@globalworking.net","label":"Miriam.Svendsen@globalworking.net"},{"href":"tel:+4791900649","label":"+47 919 00 649"},{"href":"mailto:Gro.anette@globalworking.net","label":"Gro.anette@globalworking.net"},{"href":"tel:+4740898448","label":"+47 408 98 448"}],"Selskapet":[{"href":"/om-oss","label":"Om oss"},{"href":"/nyheter","label":"Nyheter"},{"href":"/kontakt","label":"Kontakt"},{"href":"/#personvern","label":"Personvern"}],"Tjenester":[{"href":"/vr-rekrutteringsmodell","label":"VГѓВҐr rekrutteringsmodell"},{"href":"/helse","label":"Helsesektor"},{"href":"/talentportalen","label":"Talentportalen"},{"href":"/kontakt","label":"Kontakt"}]},"social":[{"href":"https://www.linkedin.com/company/globalworking-norge","label":"LinkedIn"},{"href":"https://www.instagram.com/globalworkingnorge","label":"Instagram"}]},"godeGrunner":{"articleLink":"/nyheter/sor-fron-integrasjon","articleLinkLabel":"Les artikkel","description":"Mangelen pГѓВҐ helsepersonell kombinert med sykefravГѓВ¦r og permisjoner gjГѓВёr det nГѓВёdvendig ГѓВҐ finne varige lГѓВёsninger pГѓВҐ arbeidskraft for ГѓВҐ gi pasientene oppfГѓВёlgingen de trenger.","heading":"Hva sier kommunene vi samarbeider med?","label":"Et samarbeid som gir nye lГѓВёsninger","testimonials":[{"author":"Karin, ГѓвЂ¦mot kommune","quote":"Vi har vГѓВ¦rt veldig fornГѓВёyd med to av vГѓВҐre sykepleiere fra Spania. SprГѓВҐket var mye bedre enn forventet, og de passet godt inn hos oss."},{"author":"Daniel, Kautokeino kommune","quote":"Vi fant en god lГѓВёsning med ГѓВҐ la en sykepleier jobbe i helsefagarbeider-stilling til hun var bedre i sprГѓВҐket. Tre-fire uker etterpГѓВҐ var hun klar til ГѓВҐ jobbe fast som sykepleier hos oss."},{"author":"Anne, Trondheim kommune","quote":"Vi var veldig glade for ГѓВҐ fГѓВҐ en sykepleier fra Italia som en del av teamet vГѓВҐrt. Han lГѓВ¦rte seg sprГѓВҐket fort nГѓВҐr han begynte ГѓВҐ jobbe."}]},"helseHero":{"description":"Vi forbereder helsepersonell for den norske helsesektoren Гўв‚¬вЂњ fra sprГѓВҐkopplГѓВ¦ring til trygg oppstart i jobb.","h1":"Tjenester for helseinstitusjoner"},"helsePartnership":{"cta1":"Kontakt oss","cta2":"Se kandidatportalen","heading":"Slik samarbeider vi med dere","label":"Samarbeidsmodell","p1":"Global Working er ikke et bemanningsbyrГѓВҐ. Vi forbereder kandidatene gjennom strukturert opplГѓВ¦ring. Deretter ansetter dere kandidaten direkte Гўв‚¬вЂњ uten mellomledd.","p2":"Gjennom vГѓВҐr nye kandidatportal kan arbeidsgivere selv se tilgjengelige kandidater og invitere til intervju."},"helsePhases":{"description":"VГѓВҐr prosess er delt inn i tre faser for ГѓВҐ sikre at kandidatene er godt forberedt fГѓВёr de starter i jobb.","heading":"Slik rekrutterer vi sykepleiere til Norge","label":"Rekrutteringsprosessen","phases":[{"description":"Kandidatene gjennomfГѓВёrer opptil 600 undervisningstimer i norsk, helseterminologi og praktisk sprГѓВҐkbruk i kliniske situasjoner.","formats":[{"duration":"5 mГѓВҐneder","label":"Fysisk i Alicante"},{"duration":"7 mГѓВҐneder","label":"Kombinasjon fysisk og nett"},{"duration":"9 mГѓВҐneder","label":"Full nettbasert opplГѓВ¦ring"}],"number":"01","title":"SprГѓВҐk og faglig forberedelse"},{"description":"1Гўв‚¬вЂњ4 uker etter avsluttet opplГѓВ¦ring gjennomfГѓВёres intervju med arbeidsgivere. Vi koordinerer oppstart og avreisedato med begge parter.","formats":null,"number":"02","title":"Strukturert overgang"},{"description":"Ved behov tilrettelegger vi individuell sprГѓВҐktrening fГѓВёr og etter avreise. Vi kjГѓВёrer 17Гўв‚¬вЂњ20 opplГѓВ¦ringsgrupper ГѓВҐrlig for ГѓВҐ sikre kontinuitet.","formats":null,"number":"03","title":"Ekstra oppfГѓВёlging"}]},"helsesektorComp":{"blockquote":{"author":"Kristina S, VГѓВҐgГѓВҐ kommune","text":"Vi ГѓВёnsket ГѓВҐ tilby 6 sykepleiere fast stilling gjennom samarbeid med Global Working. For oss ble dette en god lГѓВёsning pГѓВҐ bemanningskrisen vi hadde."},"ctaLabel":"Be om kandidater","description":"Global Working er den stГѓВёrste leverandГѓВёren av sykepleiere utenfra Skandinavia til Norge. Siden 2014 har vi spesialisert oss pГѓВҐ ГѓВҐ utdanne og kvalifisere sykepleiere for arbeid i Norge.","features":[{"description":"Kandidatene fГѓВҐr opptil 600 undervisningstimer i norsk, helseterminologi og praktisk sprГѓВҐkbruk i kliniske situasjoner.","title":"SprГѓВҐk og faglig forberedelse fГѓВёr ansettelse"},{"description":"Fysisk i Alicante (5 mГѓВҐneder), kombinasjon fysisk og nett (7 mГѓВҐneder), eller full nettbasert opplГѓВ¦ring (9 mГѓВҐneder).","title":"Tre opplГѓВ¦ringsmodeller"},{"description":"Intervju skjer 1Гўв‚¬вЂњ4 uker etter avsluttet opplГѓВ¦ring. Vi koordinerer oppstart og avreisedato med begge parter.","title":"Strukturert overgang til arbeidsgiver"},{"description":"Vi kan tilrettelegge individuell sprГѓВҐktrening fГѓВёr og etter avreise for ГѓВҐ redusere usikkerhet i oppstarten.","title":"Ekstra oppfГѓВёlging ved behov"}],"groupsLabel":"grupper ГѓВҐrlig","groupsValue":"17Гўв‚¬вЂњ20","heading":"Vi forbereder helsepersonell for den norske helsesektoren","label":"Tjenester for helseinstitusjoner","stats":[{"label":"erfaring i Norge","value":"10+ ГѓВҐr"},{"label":"undervisningstimer i norsk","value":"25 000+"},{"label":"timer opplГѓВ¦ring (opptil)","value":"600"}]},"hero":{"badge":"Norges ledende rekrutteringspartner","cta1":"Slik jobber vi","cta2":"Kontakt oss","description":"Global Working er verdens stГѓВёrste sprГѓВҐkskole som underviser i norsk utenfor Skandinavia. Vi spesialiserer oss pГѓВҐ norsk sprГѓВҐk- og kulturopplГѓВ¦ring for sГѓВёreuropeiske fagfolk, og kobler dem med arbeidsgivere i Norge. Vi fГѓВёlger kandidatene fra fГѓВёrste norsktime til trygg oppstart i jobb.","h1First":"Har dere behov for","h1Highlight":"arbeidskraft?","stats":[{"animate":false,"label":"Grunnlagt","value":"2014"},{"animate":true,"label":"Ansatte","value":"50+"},{"animate":true,"label":"Kandidater plassert i Norge","value":"500+"},{"animate":true,"label":"Retensjonsgrad","value":"95%"}]},"homeContact":{"cta":"Send oss en melding","description":"Du treffer oss pГѓВҐ e-post eller telefon. Vi tar kontakt sГѓВҐ snart vi har mulighet.","heading":"ГѓЛњnsker du ГѓВҐ vite mer?","label":"Kontakt"},"homeHealth":{"cta":"Les mer om helse","description":"Global Working er den stГѓВёrste leverandГѓВёren av sykepleiere utenfra Skandinavia til Norge. Siden 2014 har vi spesialisert oss pГѓВҐ ГѓВҐ utdanne og kvalifisere sykepleiere fra Spania, Italia og Frankrike for arbeid i norsk helsesektor.","heading":"Vi stГѓВёtter det norske helsevesenet","label":"Helsesektoren"},"homeServices":{"description":"Vi kobler norske arbeidsgivere med kvalifiserte fagfolk fra SГѓВёr-Europa Гўв‚¬вЂњ forberedt med sprГѓВҐk, kultur og fagkompetanse.","heading":"VГѓВҐrt tilbud til norske arbeidsgivere","label":"VГѓВҐre tjenester","sections":[{"description":"Vi finner, forbereder og fГѓВёlger opp fagfolk fra SГѓВёr-Europa til trygg oppstart i Norge. Opptil 600 timer norskopplГѓВ¦ring.","href":"/vr-rekrutteringsmodell","title":"VГѓВҐr rekrutteringsmodell"},{"description":"Norges stГѓВёrste leverandГѓВёr av sykepleiere utenfra Skandinavia. Spesialisert helsefaglig forberedelse siden 2014.","href":"/helse","title":"Helsesektor"},{"description":"Se tilgjengelige kandidater for fast ansettelse direkte i vГѓВҐr nye kandidatportal.","href":"/talentportalen","title":"Talentportalen"},{"description":"Grunnlagt i 2014. 50+ ansatte. ISO-sertifisert. Hovedkontor i Alicante med kontor i Oslo.","href":"/om-oss","title":"Om Global Working"}]},"homeStats":[{"label":"Kandidater plassert i Norge","value":"500+"},{"label":"Retensjonsgrad","value":"95%"},{"label":"Undervisningstimer i norsk","value":"25 000+"}],"hvaGjor":{"ctaLabel":"Book et mГѓВёte med oss","ctaNote":"Uforpliktende kartlegging av behov","description":"Vi finner og presenterer de mest relevante menneskene til din virksomhet, og fГѓВёlger prosessen helt frem til trygg oppstart.","heading":"Hva gjГѓВёr Global Working?","label":"VГѓВҐr prosess","services":[{"description":"Vi rekrutterer kompetansen dere trenger innen flere sektorer, blant annet helse og omsorg, industri og bygg, samt utdanning og barneomsorg.","title":"Rekrutterer kompetanse"},{"description":"Vi underviser fra ingen forkunnskaper til opptil B2-nivГѓВҐ, og tilpasser sprГѓВҐk, rolle og arbeidshverdag til mГѓВҐlene dere har satt.","title":"SГѓВёrger for ГѓВёnsket sprГѓВҐknivГѓВҐ"},{"description":"Vi hjelper kandidatene gjennom hele prosessen med nГѓВёdvendige dokumenter og riktig papirarbeid, med ekstra sprГѓВҐktimer ved behov.","title":"Trygg oppstart i Norge"}]},"kontaktComp":{"description":"Du treffer oss pГѓВҐ e-post eller telefon, eller ved ГѓВҐ fylle ut skjemaet under. Vi tar kontakt sГѓВҐ snart vi har mulighet.","heading":"ГѓЛњnsker du ГѓВҐ vite mer?","label":"Kontakt","officeAddress":"Carrer de Periodista Pirula Arderius, 4, 03001 Alicante, EspaГѓВ±a","officeTitle":"Hovedkontor Alicante"},"kontaktHero":{"description":"Vi er tilgjengelige for spГѓВёrsmГѓВҐl om rekruttering, samarbeid og kandidatportal. Ta kontakt Гўв‚¬вЂњ vi svarer normalt innen 1 virkedag.","h1":"Kontakt oss"},"navbar":{"ctaLabel":"Kom i gang","links":[{"href":"/vr-rekrutteringsmodell","label":"VГѓВҐr rekrutteringsmodell"},{"href":"/helse","label":"Helsesektor"},{"href":"/nyheter","label":"Nyheter"},{"href":"/talentportalen","label":"Talentportalen"},{"href":"/om-oss","label":"Om oss"},{"href":"/kontakt","label":"Kontakt"}]},"nyheterHero":{"description":"FГѓВёlg med pГѓВҐ siste nytt fra Global Working Гўв‚¬вЂњ artikler, oppdateringer og historier fra vГѓВҐrt arbeid med rekruttering og sprГѓВҐkopplГѓВ¦ring.","h1":"Nyheter & Artikler"},"omOssComp":{"blockquote":{"author":"Pablo, CEO Global Working","text":"For oss handler internasjonal rekruttering ikke bare om ГѓВҐ fylle en stilling. Det handler om ГѓВҐ forberede mennesker grundig, slik at bГѓВҐde arbeidsgiver og kandidat fГѓВҐr en trygg start og et langsiktig samarbeid."},"heading":"Hvem er Global Working?","label":"Om oss","locationLabel":"Alicante","locationSub":"Hovedkontor med kontor i Oslo","p1":"Global Working er en spesialisert aktГѓВёr innen sprГѓВҐkopplГѓВ¦ring og internasjonal rekruttering i Europa. Vi forbereder kandidater fГѓВёr ansettelse, slik at arbeidsgivere fГѓВҐr medarbeidere og grunnlag for varige ansettelser.","p2":"Global Working ble etablert i 2014 med mГѓВҐl om ГѓВҐ gjГѓВёre det enklere for fagpersoner ГѓВҐ bevege seg i det europeiske arbeidsmarkedet. I dag kombinerer vi rekruttering, sprГѓВҐkopplГѓВ¦ring og tett oppfГѓВёlging for ГѓВҐ sikre forutsigbare og bГѓВ¦rekraftige ansettelser.","stats":[{"label":"Etablert","value":"2014"},{"label":"Ansatte","value":"50"},{"label":"Sertifisert","value":"ISO"}],"values":[{"desc":"25 % av teamet er psykologer som jobber med seleksjon, vurdering og oppfГѓВёlging av kandidater.","title":"Seleksjon med faglig vurdering"},{"desc":"55 % av teamet er sprГѓВҐklГѓВ¦rere med spesialisering i yrkesrettet sprГѓВҐkopplГѓВ¦ring.","title":"Yrkesrettet sprГѓВҐkopplГѓВ¦ring"},{"desc":"Vi er ISO-sertifisert for sprГѓВҐkundervisning og internasjonal rekruttering i Europa.","title":"Kvalitetssikret prosess"}]},"omOssHero":{"description":"Global Working er en spesialisert aktГѓВёr innen sprГѓВҐkopplГѓВ¦ring og internasjonal rekruttering.","h1":"Om oss"},"omOssOffices":{"description":"Global Working har hovedkontor i Alicante, Spania, med kontor i Oslo.","heading":"VГѓВҐre kontorer","label":"Lokasjon","officeAddress":"Carrer de Periodista Pirula Arderius, 4, 03001 Alicante, EspaГѓВ±a","officeName":"Hovedkontor Гўв‚¬вЂќ Alicante"},"omOssTeam":{"description":"VГѓВҐrt flerfaglige team av psykologer, sprГѓВҐklГѓВ¦rere og rekrutteringsspesialister sikrer en helhetlig prosess Гўв‚¬вЂќ fra utvelgelse og opplГѓВ¦ring til oppfГѓВёlging i Norge.","heading":"MГѓВёt teamet i Global Working","label":"VГѓВҐrt team","members":[{"hasImage":true,"initials":"PS","name":"Pablo Santamarina","role":"CEO & Grunnlegger"},{"hasImage":false,"initials":"MS","name":"Miriam Svendsen","role":"Rekrutteringsansvarlig"},{"hasImage":false,"initials":"GA","name":"Gro Anette","role":"KandidatoppfГѓВёlging"},{"hasImage":false,"initials":"T","name":"Teamet","role":"50+ ansatte i Alicante og Oslo"}]},"rekrutteringCollab":{"cta1":"Kontakt oss","cta2":"Se kandidatportalen","heading":"Slik samarbeider vi med dere","label":"Samarbeidsmodell","p1":"Global Working er ikke et bemanningsbyrГѓВҐ. Vi forbereder kandidatene gjennom strukturert opplГѓВ¦ring. Deretter ansetter dere kandidaten direkte Гўв‚¬вЂњ uten mellomledd.","p2":"Samarbeidet starter med en uforpliktende kartlegging av ditt behov. Vi presenterer sГѓВҐ kvalifiserte kandidater som matcher kravene dere har satt.","p3":"Gjennom vГѓВҐr nye kandidatportal kan arbeidsgivere selv se tilgjengelige kandidater og invitere til intervju."},"rekrutteringComp":{"badge":"Strukturert modell siden 2014","heading":"Slik rekrutterer vi fagfolk til Norge","label":"VГѓВҐr rekrutteringsmodell","p1":"VГѓВҐre kandidater kommer hovedsakelig fra Spania, Italia og Frankrike, og er motiverte fagpersoner som ГѓВёnsker ГѓВҐ jobbe i Norge over lengre tid eller etablere seg her pГѓВҐ sikt.","p2":"Undervisningen kan gjennomfГѓВёres fysisk i Alicante (5 mГѓВҐneder), som kombinasjon av fysisk og nettbasert undervisning (7 mГѓВҐneder), eller fullt nettbasert (9 mГѓВҐneder).","sectors":["Helse og omsorg","Industri og bygg","Utdanning","Barneomsorg"],"steps":[{"description":"Vi kartlegger kompetanse, motivasjon og ГѓВёnsker fГѓВёr kandidatene presenteres for arbeidsgiver.","title":"Rekrutterer kompetansen du trenger"},{"description":"Alle kandidater fГѓВёlger et strukturert lГѓВёp med opptil 600 timer norsk, bransjeterminologi og arbeidskultur.","title":"SprГѓВҐk og faglig forberedelse"},{"description":"1Гўв‚¬вЂњ4 uker etter opplГѓВ¦ring gjennomfГѓВёres intervju med arbeidsgivere, og oppstart og avreisedato avtales.","title":"Strukturert overgang"},{"description":"Ved behov tilrettelegger vi individuelt opplegg med ekstra sprГѓВҐktrening fГѓВёr eller etter avreise.","title":"Ekstra oppfГѓВёlging ved behov"}]},"rekrutteringHero":{"description":"Vi finner og presenterer de mest relevante menneskene til din virksomhet, og fГѓВёlger prosessen helt frem til trygg oppstart.","h1":"Hva gjГѓВёr Global Working?"},"talentportalenBenefits":{"heading":"Fordeler med kandidatportalen","items":["Sanntidsoversikt over tilgjengelige kandidater","Detaljerte profiler med sprГѓВҐknivГѓВҐ og erfaring","Direkte kommunikasjon med rekrutteringsteamet","Gratis tilgang for arbeidsgivere som samarbeider med oss"],"label":"Hvorfor portalen"},"talentportalenComp":{"benefits":[{"desc":"FГѓВҐ oversikt over tilgjengelige kandidater og finn profiler som passer deres behov.","title":"Se kandidater for fast ansettelse"},{"desc":"Arbeidsgivere kan selv gГѓВҐ gjennom profiler og invitere aktuelle kandidater til intervju.","title":"Inviter til intervju direkte"},{"desc":"Se status i sprГѓВҐk- og faglig forberedelse, slik at oppstarten kan planlegges tryggere.","title":"Oversikt over sprГѓВҐkforberedelse"},{"desc":"Portalen er koblet til rekrutteringsteamet vГѓВҐrt for korte avklaringer underveis.","title":"Rask dialog med oss"}],"ctaContact":"Kontakt oss","ctaLogin":"Logg inn pГѓВҐ portalen","description":"Global Working har fГѓВҐtt ny kandidatportal. NГѓВҐ kan du selv gГѓВҐ inn og se hvilke kandidater vi har tilgjengelig for fast ansettelse.","heading":"Ny kandidatportal for arbeidsgivere","label":"Talentportalen","portalUrl":"https://globalworking-talentportal.lovable.app"},"talentportalenHero":{"description":"Se tilgjengelige kandidater og inviter til intervju direkte gjennom vГѓВҐr nye plattform.","h1":"Kandidatportal for arbeidsgivere"},"talentportalenSteps":{"heading":"Slik bruker du portalen","label":"Steg for steg","steps":[{"desc":"Ta kontakt med oss for ГѓВҐ fГѓВҐ tilgang til kandidatportalen.","number":"01","title":"Opprett konto"},{"desc":"Se profiler, sprГѓВҐknivГѓВҐ, fagbakgrunn og tilgjengelighet.","number":"02","title":"Bla gjennom kandidater"},{"desc":"Velg kandidater som passer og inviter dem direkte til intervju.","number":"03","title":"Inviter til intervju"},{"desc":"Dere ansetter kandidaten direkte Гўв‚¬вЂњ uten mellomledd.","number":"04","title":"Ansett direkte"}]}}'::jsonb, now(), null)
